import { useState, useEffect, useRef, useCallback } from 'react';
import {
  getAuthToken,
  getPermissionsCacheEntry,
  PERMISSION_READY,
} from '@linm-soft/common-components';
import { appSettings } from '../config/appSettings';
import { isStandalone } from '../dev/isStandalone';

// ─── Types (mirrors nav MFE's UserPermissionPayload) ─────────────────────────

interface NavItemDto {
  code: string;
  path: string | null;
}

export interface AdminPermissionPayload {
  menuItemCodes: string[];
  permissionCodes: string[];
  navItems: NavItemDto[];
  allowedPaths?: string[];
  issuedAt: number;
}

// ─── Shared permission cache (same envelope as nav MFE) ───────────────────────

function readFromCache(): AdminPermissionPayload | null {
  try {
    const cached = getPermissionsCacheEntry();
    if (!cached?.payload) return null;
    const p = cached.payload;
    const menuItemCodes = p.menuItemCodes;
    const permissionCodes = p.permissionCodes;
    if (!Array.isArray(menuItemCodes) || !Array.isArray(permissionCodes)) return null;
    const allowedPaths = p.allowedPaths;
    return {
      menuItemCodes: menuItemCodes as string[],
      permissionCodes: permissionCodes as string[],
      navItems: (Array.isArray(p.navItems) ? p.navItems : []) as NavItemDto[],
      allowedPaths: Array.isArray(allowedPaths)
        ? (allowedPaths as string[]).filter((x) => typeof x === 'string')
        : undefined,
      issuedAt: typeof p.issuedAt === 'number' ? p.issuedAt : 0,
    };
  } catch {
    return null;
  }
}

function hasRouteList(payload: AdminPermissionPayload | null): boolean {
  if (!payload) return false;
  if (payload.allowedPaths?.length) return true;
  return payload.navItems.some((i) => !!i.path && i.path !== '#');
}

async function fetchPayload(
  apiBase: string,
  currentPath: string,
): Promise<AdminPermissionPayload | null> {
  const token = getAuthToken();
  if (!token) return null;
  const pathParam = encodeURIComponent(currentPath);
  try {
    const res = await fetch(
      `${apiBase}/admin/users/me/permissions?currentPath=${pathParam}`,
      { headers: { Authorization: `Bearer ${token}` } },
    );
    if (!res.ok) return null;
    const json = await res.json();
    const data = json?.data ?? json;
    if (!data?.menuItemCodes) return null;
    return data as AdminPermissionPayload;
  } catch {
    return null;
  }
}

// ─── Hook ─────────────────────────────────────────────────────────────────────

const STANDALONE_ADMIN_PATHS = [
  '/admin',
  '/admin/accounts',
  '/admin/companies',
  '/admin/permissions',
  '/admin/data-cleanup',
  '/admin/jobs',
  '/admin/jobs/schedule',
  '/admin/jobs/dashboard',
  '/admin/jobs/inbound',
  '/admin/jobs/external-sync',
  '/admin/jobs/external-runs',
  '/admin/jobs/outbound',
  '/admin/jobs/internal',
];

const STANDALONE_PAYLOAD: AdminPermissionPayload = {
  menuItemCodes: [],
  permissionCodes: [],
  navItems: [],
  allowedPaths: STANDALONE_ADMIN_PATHS,
  issuedAt: Date.now(),
};

export interface UseAdminPermissionsResult {
  payload: AdminPermissionPayload | null;
  loading: boolean;
  /** True if the given path is covered by the user's navItems */
  hasMenuAccess: (path: string) => boolean;
  /** True if permissionCodes includes the given code */
  hasPermission: (code: string) => boolean;
  /** True if menuItemCodes includes the given menuId */
  hasMenuItem: (code: string) => boolean;
  refresh: () => void;
}

export function useAdminPermissions(): UseAdminPermissionsResult {
  const [payload, setPayload] = useState<AdminPermissionPayload | null>(() =>
    isStandalone ? STANDALONE_PAYLOAD : readFromCache(),
  );
  const [loading, setLoading] = useState(() =>
    isStandalone ? false : !hasRouteList(readFromCache()),
  );
  const mountedRef = useRef(true);
  const cancelRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const applyCache = useCallback(() => {
    if (isStandalone) return true;
    const cached = readFromCache();
    if (cached && hasRouteList(cached)) {
      setPayload(cached);
      setLoading(false);
      return true;
    }
    return false;
  }, []);

  const load = useCallback(async (force = false) => {
    if (isStandalone) return;
    if (!force && applyCache()) return;

    setLoading(true);
    const currentPath =
      typeof window !== 'undefined'
        ? window.location.pathname || '/admin/accounts'
        : '/admin/accounts';
    const result = await fetchPayload(appSettings.apiUrl, currentPath);
    if (!mountedRef.current) return;

    if (result && hasRouteList(result)) {
      setPayload(result);
      setLoading(false);
      return;
    }

    if (applyCache()) return;

    if (result) setPayload(result);
    setLoading(false);
  }, [applyCache]);

  const refresh = useCallback(() => {
    if (isStandalone) return;
    if (cancelRef.current) clearTimeout(cancelRef.current);
    cancelRef.current = setTimeout(() => { load(true); }, 0);
  }, [load]);

  useEffect(() => {
    if (isStandalone) return undefined;
    mountedRef.current = true;
    if (cancelRef.current) clearTimeout(cancelRef.current);
    cancelRef.current = setTimeout(() => { load(); }, 0);

    const onAuthChanged = () => {
      if (cancelRef.current) clearTimeout(cancelRef.current);
      cancelRef.current = setTimeout(() => { load(true); }, 0);
    };
    const onPermissionReady = () => {
      applyCache();
    };

    window.addEventListener('linm:auth:changed', onAuthChanged);
    window.addEventListener('linm:permission:changed', onAuthChanged);
    window.addEventListener(PERMISSION_READY, onPermissionReady);

    return () => {
      mountedRef.current = false;
      if (cancelRef.current) clearTimeout(cancelRef.current);
      window.removeEventListener('linm:auth:changed', onAuthChanged);
      window.removeEventListener('linm:permission:changed', onAuthChanged);
      window.removeEventListener(PERMISSION_READY, onPermissionReady);
    };
  }, [load, applyCache]);

  useEffect(() => {
    if (isStandalone) return undefined;
    const onRoute = () => {
      applyCache();
      if (typeof window !== 'undefined' && window.location.pathname.startsWith('/admin')) {
        if (cancelRef.current) clearTimeout(cancelRef.current);
        cancelRef.current = setTimeout(() => { load(true); }, 0);
      }
    };
    window.addEventListener('single-spa:routing-event', onRoute);
    window.addEventListener(PERMISSION_READY, onRoute);
    return () => {
      window.removeEventListener('single-spa:routing-event', onRoute);
      window.removeEventListener(PERMISSION_READY, onRoute);
    };
  }, [load, applyCache]);

  const hasMenuAccess = useCallback((path: string): boolean => {
    if (isStandalone) return true;
    if (!payload) return false;
    const paths = payload.allowedPaths?.length
      ? payload.allowedPaths
      : (payload.navItems.map((i) => i.path).filter(Boolean) as string[]);
    if (!paths.length) return false;

    const normalized = path.replace(/\/$/, '') || '/';
    if (normalized === '/admin') {
      return paths.some((p) => p === '/admin' || p.startsWith('/admin/'));
    }

    return paths.some(
      (p) => normalized === p || normalized.startsWith(`${p}/`),
    );
  }, [payload]);

  const hasPermission = useCallback((code: string): boolean => {
    if (isStandalone) return true;
    return payload?.permissionCodes.includes(code) ?? false;
  }, [payload]);

  const hasMenuItem = useCallback((code: string): boolean => {
    if (isStandalone) return true;
    return payload?.menuItemCodes.includes(code) ?? false;
  }, [payload]);

  return { payload, loading, hasMenuAccess, hasPermission, hasMenuItem, refresh };
}
