import { apiClient } from './api';
import { BffResponse, unwrap } from '@linm-soft/common-components';

export interface CompanyItem {
  id: string;
  code: string;
  name: string;
  shortName?: string;
  logoUrl?: string;
  address?: string;
  phone?: string;
  email?: string;
  isActive: boolean;
  createdAt: string;
  updatedAt?: string;
}

export interface ActiveCompanyItem {
  id: string;
  code?: string;
  name: string;
  shortName?: string;
  logoUrl?: string;
}

export interface CreateCompanyRequest {
  code: string;
  name: string;
  shortName?: string;
  logoUrl?: string;
  address?: string;
  phone?: string;
  email?: string;
  isActive?: boolean;
}

export interface UpdateCompanyRequest {
  name: string;
  shortName?: string;
  logoUrl?: string;
  address?: string;
  phone?: string;
  email?: string;
  isActive?: boolean;
}

export const companyService = {
  getAll: (): Promise<CompanyItem[]> =>
    apiClient.get<BffResponse<CompanyItem[]>>('/companies').then(unwrap),

  getById: (id: string): Promise<CompanyItem> =>
    apiClient.get<BffResponse<CompanyItem>>(`/companies/${id}`).then(unwrap),

  getActiveList: (): Promise<ActiveCompanyItem[]> =>
    apiClient.get<BffResponse<ActiveCompanyItem[]>>('/companies/active-list').then(unwrap),

  create: (payload: CreateCompanyRequest): Promise<CompanyItem> =>
    apiClient.post<BffResponse<CompanyItem>>('/companies', payload).then(unwrap),

  update: (id: string, payload: UpdateCompanyRequest): Promise<CompanyItem> =>
    apiClient.put<BffResponse<CompanyItem>>(`/companies/${id}`, payload).then(unwrap),

  toggleStatus: (id: string): Promise<CompanyItem> =>
    apiClient.patch<BffResponse<CompanyItem>>(`/companies/${id}/toggle-status`).then(unwrap),

  delete: (id: string): Promise<void> =>
    apiClient.delete<void>(`/companies/${id}`).then(() => undefined),
};
