import React from 'react';
import { Link, useLocation } from 'react-router-dom';
import { useNavTitle } from '@linm-soft/common-components';
import { StatsCard, StatsCardsGrid, TableCard } from '../../ui';
import { jobsService, type JobDirection, type PlatformJobDashboardStats } from '../../services/jobs';
import { JobEventTypeFilter } from './components/JobEventTypeFilter';
import { useAppToast } from '../../hooks/useAppToast';

const directionTitles: Record<string, string> = {
  inbound: 'Inbound',
  outbound: 'Outbound',
  internal: 'Internal',
};

const JobDashboardPage: React.FC = () => {
  const location = useLocation();
  const path = location.pathname.toLowerCase();
  const direction = (path.includes('/inbound')
    ? 'Inbound'
    : path.includes('/outbound')
      ? 'Outbound'
      : path.includes('/internal')
        ? 'Internal'
        : '') as JobDirection | '';

  const dirKey = path.includes('/inbound') ? 'inbound' : path.includes('/outbound') ? 'outbound' : '';
  useNavTitle(direction ? `Job dashboard — ${directionTitles[dirKey] ?? direction}` : 'Job dashboard');
  const toast = useAppToast();

  const [stats, setStats] = React.useState<PlatformJobDashboardStats[]>([]);
  const [eventTypes, setEventTypes] = React.useState<Awaited<ReturnType<typeof jobsService.getEventTypes>>>([]);
  const [eventType, setEventType] = React.useState('');
  const [status, setStatus] = React.useState('');
  const [events, setEvents] = React.useState<Awaited<ReturnType<typeof jobsService.getEvents>>['items']>([]);
  const [loading, setLoading] = React.useState(false);

  const load = React.useCallback(() => {
    setLoading(true);
    const t = setTimeout(() => {
      Promise.all([
        jobsService.getDashboard({ direction: direction || undefined, eventType: eventType || undefined }),
        jobsService.getEventTypes(direction || undefined),
        jobsService.getEvents({
          page: 1,
          pageSize: 25,
          direction: direction || undefined,
          eventType: eventType || undefined,
          processingStatus: status || undefined,
        }),
      ])
        .then(([dash, types, ev]) => {
          setStats(dash);
          setEventTypes(types);
          setEvents(ev.items);
        })
        .catch((e: Error) => toast.error(e.message))
        .finally(() => setLoading(false));
    }, 0);
    return () => clearTimeout(t);
  }, [direction, eventType, status, toast]);

  React.useEffect(() => load(), [load]);

  const primary = stats.find((s) => !direction || s.direction === direction) ?? stats[0];

  return (
    <div data-testid="job-dashboard-page">
      <p style={{ marginBottom: 12 }}>
        <Link to="/admin/jobs">← Job monitoring</Link>
        {' · '}
        <Link to="/admin/jobs/schedule">Cấu hình lịch</Link>
        {' · '}
        <Link to="/admin/jobs/external-sync">Cấu hình sync REVA</Link>
        {' · '}
        <Link to="/admin/jobs/external-runs">Theo dõi sync ngoài</Link>
        {' · '}
        <Link to="/admin/jobs/internal">Job nội bộ</Link>
      </p>

      <JobEventTypeFilter
        eventTypes={eventTypes}
        eventType={eventType}
        onEventTypeChange={setEventType}
        status={status}
        onStatusChange={setStatus}
      />

      {primary?.isPlaceholder ? (
        <p style={{ color: '#666', marginBottom: 16 }}>{primary.placeholderMessage}</p>
      ) : null}

      {primary && !primary.isPlaceholder ? (
        <StatsCardsGrid>
          <StatsCard label="Tổng" value={primary.total} variant="total" loading={loading} />
          <StatsCard label="Pass (Completed)" value={primary.completed} variant="success" loading={loading} />
          <StatsCard label="Fail" value={primary.failed} variant="danger" loading={loading} />
          <StatsCard label="Retry pending" value={primary.retryPending} variant="warning" loading={loading} />
        </StatsCardsGrid>
      ) : null}

      {!direction && stats.length > 0 ? (
        <div style={{ marginTop: 24 }}>
          <h3>Theo hướng</h3>
          <StatsCardsGrid>
            {stats.map((s) => (
              <StatsCard
                key={s.direction}
                label={s.direction}
                value={s.isPlaceholder ? '—' : s.total}
                variant="total"
                loading={loading}
              />
            ))}
          </StatsCardsGrid>
        </div>
      ) : null}

      <div style={{ marginTop: 24 }}>
        <h3>Event gần đây</h3>
        <TableCard>
          {loading ? (
            <p>Đang tải…</p>
          ) : events.length === 0 ? (
            <p>Không có event</p>
          ) : (
            <table style={{ width: '100%', borderCollapse: 'collapse' }}>
              <thead>
                <tr>
                  <th align="left">Event type</th>
                  <th align="left">Status</th>
                  <th align="left">Attempt</th>
                  <th align="left">Created</th>
                </tr>
              </thead>
              <tbody>
                {events.map((e) => (
                  <tr key={e.eventId}>
                    <td>{e.eventType}</td>
                    <td>{e.processingStatus}</td>
                    <td>
                      {e.attemptCount}/{e.maxAttempts}
                    </td>
                    <td>{new Date(e.createdAt).toLocaleString('vi-VN')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </TableCard>
      </div>
    </div>
  );
};

export default JobDashboardPage;
